```javascript
class ButtonController {
  constructor(buttonElement) {
    this.button = buttonElement;
  }

  setLoading(isLoading) {
    if (isLoading) {
      this.button.setAttribute('data-state', 'loading');
      this.button.setAttribute('aria-busy', 'true');
    } else {
      this.button.setAttribute('data-state', 'default');
      this.button.setAttribute('aria-busy', 'false');
    }
  }

  setDisabled(isDisabled) {
    this.button.setAttribute('data-state', isDisabled ? 'disabled' : 'default');
  }
}

// Usage
const button = document.querySelector('.c-button');
const controller = new ButtonController(button);

// On form submission
controller.setLoading(true);
// After async operation completes
controller.setLoading(false);
```

