### JavaScript for Keyboard Navigation

```javascript
// Keyboard navigation handler for c-navigation
document.querySelectorAll('.c-navigation').forEach(nav => {
  const links = nav.querySelectorAll('.c-navigation__link');
  let currentIndex = Array.from(links).findIndex(
    link => link.getAttribute('aria-current') === 'page'
  );

  // If no current page, start at first link
  if (currentIndex === -1) currentIndex = 0;

  nav.addEventListener('keydown', (e) => {
    switch(e.key) {
      case 'ArrowRight':
      case 'ArrowDown':
        e.preventDefault();
        // Move focus to next link
        links[currentIndex].setAttribute('tabindex', '-1');
        currentIndex = (currentIndex + 1) % links.length;
        links[currentIndex].setAttribute('tabindex', '0');
        links[currentIndex].focus();
        break;

      case 'ArrowLeft':
      case 'ArrowUp':
        e.preventDefault();
        // Move focus to previous link
        links[currentIndex].setAttribute('tabindex', '-1');
        currentIndex = (currentIndex - 1 + links.length) % links.length;
        links[currentIndex].setAttribute('tabindex', '0');
        links[currentIndex].focus();
        break;

      case 'Home':
        e.preventDefault();
        // Move focus to first link
        links[currentIndex].setAttribute('tabindex', '-1');
        currentIndex = 0;
        links[currentIndex].setAttribute('tabindex', '0');
        links[currentIndex].focus();
        break;

      case 'End':
        e.preventDefault();
        // Move focus to last link
        links[currentIndex].setAttribute('tabindex', '-1');
        currentIndex = links.length - 1;
        links[currentIndex].setAttribute('tabindex', '0');
        links[currentIndex].focus();
        break;
    }
  });
});
```

